import { CommonModule } from '@angular/common';
import { Component } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../services/auth.service';
import { CartService } from '../services/cart.service';

@Component({
  selector: 'app-auth-page',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    <div class="detail">
      <section class="detail__panel">
        <h1>Iniciar sesión</h1>
        <p>Accede para guardar tu carrito en tu cuenta.</p>

        <form (ngSubmit)="login()" class="form-grid">
          <label>Correo
            <input [(ngModel)]="loginModel.correo" name="loginCorreo" required>
          </label>
          <label>Contraseña
            <input [(ngModel)]="loginModel.password" name="loginPassword" type="password" required>
          </label>
          <button type="submit" class="back-link">Ingresar</button>
        </form>
      </section>

      <section class="detail__panel">
        <h1>Crear cuenta</h1>
        <p>Regístrate para conservar tu carrito entre dispositivos.</p>

        <form (ngSubmit)="register()" class="form-grid">
          <label>Nombre
            <input [(ngModel)]="registerModel.nombre" name="registerNombre" required>
          </label>
          <label>Correo
            <input [(ngModel)]="registerModel.correo" name="registerCorreo" required>
          </label>
          <label>Contraseña
            <input [(ngModel)]="registerModel.password" name="registerPassword" type="password" required>
          </label>
          <button type="submit" class="back-link">Registrar</button>
        </form>

        <div *ngIf="hasLocalCart" style="margin-top:1rem;">
          <p>Tienes un carrito local guardado en este navegador.</p>
          <button type="button" class="back-link" (click)="importCart()">Importar carrito a mi cuenta</button>
        </div>

        <p *ngIf="message" style="margin-top:1rem;">{{ message }}</p>
        <p *ngIf="error" style="margin-top:1rem; color:#b91c1c;">{{ error }}</p>
      </section>
    </div>
  `,
})
export class AuthPageComponent {
  loginModel = { correo: '', password: '' };
  registerModel = { nombre: '', correo: '', password: '' };
  hasLocalCart = false;
  message = '';
  error = '';

  constructor(
    private readonly auth: AuthService,
    private readonly cart: CartService,
    private readonly router: Router,
  ) {
    this.hasLocalCart = this.cart.hasLocalCart();
  }

  login(): void {
    this.error = '';
    this.message = '';

    this.auth.login(this.loginModel).subscribe({
      next: (response) => {
        this.auth.setUser(response.user);
        this.cart.loadCart();
        this.hasLocalCart = this.cart.hasLocalCart();
        this.message = 'Sesión iniciada correctamente.';
        this.router.navigateByUrl('/carrito');
      },
      error: (error) => {
        this.error = error.error?.error || 'No se pudo iniciar sesión.';
      },
    });
  }

  register(): void {
    this.error = '';
    this.message = '';

    this.auth.register(this.registerModel).subscribe({
      next: (response) => {
        this.auth.setUser(response.user);
        this.cart.loadCart();
        this.hasLocalCart = this.cart.hasLocalCart();
        this.message = 'Cuenta creada correctamente.';
        this.router.navigateByUrl('/carrito');
      },
      error: (error) => {
        this.error = error.error?.error || 'No se pudo registrar la cuenta.';
      },
    });
  }

  importCart(): void {
    this.cart.importLocalCart();
    this.hasLocalCart = this.cart.hasLocalCart();
    this.message = 'Carrito importado correctamente.';
  }
}
